import flask
# Test empty name
try:
    bp = flask.Blueprint('', __name__)
    print('FAIL: No error raised - empty name allowed!')
except ValueError as e:
    print(f'OK: Empty name raises ValueError: {e}')

# Test dot in name
try:
    bp = flask.Blueprint('test.bp', __name__)
    print('FAIL: No error raised - dot in name allowed!')
except ValueError as e:
    print(f'OK: Dot in name raises ValueError: {e}')

# Test valid name
try:
    bp = flask.Blueprint('test', __name__)
    print(f'OK: Valid name works, bp.name = {bp.name}')
except ValueError as e:
    print(f'FAIL: Valid name raised ValueError: {e}')
""}

